//line main.kuki:322
func gatherPrompt(args []string) string {
//line main.kuki:323
	prompt := ""
//line main.kuki:326
	if !isTerminal(os.Stdin) && (len(args) == 0) {
//line main.kuki:327
		data, err_49 := io.ReadAll(os.Stdin)
//line main.kuki:327
		if err_49 != nil {
//line main.kuki:327
			//line main.kuki:328
			data = []byte{}
		}
//line main.kuki:330
		prompt = strpkg.TrimSpace(string(data))
	}
//line main.kuki:332
	if len(args) > 0 {
//line main.kuki:333
		argText := strpkg.Join(args, " ")
//line main.kuki:334
		if prompt != "" {
//line main.kuki:335
			prompt = fmt.Sprintf("%v\n\n%v", argText, prompt)
		} else {
//line main.kuki:337
			prompt = argText
		}
	}
//line main.kuki:339
	return prompt
}

//line main.kuki:341
func isTerminal(f *os.File) bool {
//line main.kuki:342
	info, err := f.Stat()
//line main.kuki:343
	if err != nil {
//line main.kuki:344
		return false
	}
//line main.kuki:345
	return ((info.Mode() & 0x200000) != 0)
}

